const e=JSON.parse('{"key":"v-8b3a37e4","path":"/basics/design-patterns/","title":"SOLID原则","lang":"zh-CN","frontmatter":{"summary":"SOLID原则 SOLID原则 这五条原则是在罗伯特·马丁的著 作《敏捷软件开发：原则、模式与实践》中首次提出的。 SOLID 是让软件设计更易于理解、更加灵活和更易于维护的 五个原则的简称。与生活中所有事情一样，盲目遵守这些原则可能会弊大于利。在程序架构中应用这些原则可能会使其变得过于复杂。我对于是否真的有能够同时应用所有这五条原则的成功软件产品表示怀疑。","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-v2-demo.mrhope.site/basics/design-patterns/"}],["meta",{"property":"og:site_name","content":"Weiser"}],["meta",{"property":"og:title","content":"SOLID原则"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:updated_time","content":"2022-06-10T15:06:22.000Z"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"article:modified_time","content":"2022-06-10T15:06:22.000Z"}]]},"excerpt":"","headers":[{"level":2,"title":"SOLID原则","slug":"solid原则-1","link":"#solid原则-1","children":[{"level":3,"title":"单一职责原则","slug":"单一职责原则","link":"#单一职责原则","children":[]},{"level":3,"title":"开闭原则","slug":"开闭原则","link":"#开闭原则","children":[]},{"level":3,"title":"里氏替换原则","slug":"里氏替换原则","link":"#里氏替换原则","children":[]},{"level":3,"title":"接口隔离原则","slug":"接口隔离原则","link":"#接口隔离原则","children":[]},{"level":3,"title":"依赖倒置原则","slug":"依赖倒置原则","link":"#依赖倒置原则","children":[]}]}],"git":{"createdTime":1654587090000,"updatedTime":1654873582000,"contributors":[{"name":"xwzbupt","email":"xwze@bupt.cn","commits":3}]},"readingTime":{"minutes":5,"words":1500},"filePathRelative":"basics/design-patterns/README.md","localizedDate":"2022年6月7日"}');export{e as data};
